-- Program: Martial Arts Foundation
-- Category: Sports -> sport_specific
-- Priority: High
-- Durations: [4, 8], Sessions: [4, 5]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Martial Arts Foundation',
    'Build the physical foundation for martial arts training. Covers kick power, striking power, flexibility for high kicks, grip strength for grappling, and fight-round conditioning.',
    'sport_specific',
    'beginner',
    8,
    5,
    'push_pull_legs',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build cardiovascular endurance', 'Improve VO2 max', 'Improve flexibility']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Martial Arts Foundation - 4w 4x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Easy',
    4,
    'Martial Arts Foundation - 4w 4x/wk',
    'sport_specific',
    4,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build cardiovascular endurance', 'Improve VO2 max', 'Improve flexibility']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Martial Arts Foundation'
ON CONFLICT DO NOTHING;

